namespace sv_0903141a44b447d2ab899ad4a4e91eab.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

public record ThemeInfo(ThemeMode Mode, string AccentColor)
{
    public static ThemeInfo Default => new(ThemeMode.Light, "#0d6efd");
}

@using sv_0903141a44b447d2ab899ad4a4e91eab.Services

<span class="theme-indicator" style="color: @(Theme?.AccentColor ?? "#0d6efd");">
    @switch (Theme?.Mode)
    {
        case ThemeMode.Dark:
            <span>🌙 Dark</span>
            break;
        case ThemeMode.System:
            <span>💻 System</span>
            break;
        default:
            <span>☀️ Light</span>
            break;
    }
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }
}

@page "/settings"
@rendermode InteractiveServer
@using sv_0903141a44b447d2ab899ad4a4e91eab.Services
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card p-4" style="max-width: 500px;">
    <h4>Theme</h4>
    <div class="btn-group mb-3" role="group">
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            <button class="btn @(mode == currentMode ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => SetMode(mode)">
                @mode
            </button>
        }
    </div>

    <h4>Accent Color</h4>
    <div class="d-flex align-items-center gap-3 mb-3">
        <input type="color" class="form-control form-control-color"
               value="@currentAccent" @onchange="SetAccent" />
        <span>@currentAccent</span>
    </div>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private ThemeMode currentMode;
    private string currentAccent = ThemeInfo.Default.AccentColor;

    protected override void OnParametersSet()
    {
        if (Theme is not null)
        {
            currentMode = Theme.Mode;
            currentAccent = Theme.AccentColor;
        }
    }

    private async Task SetMode(ThemeMode mode)
    {
        currentMode = mode;
        await ThemeSource.NotifyChangedAsync(new ThemeInfo(currentMode, currentAccent));
    }

    private async Task SetAccent(ChangeEventArgs e)
    {
        currentAccent = e.Value?.ToString() ?? ThemeInfo.Default.AccentColor;
        await ThemeSource.NotifyChangedAsync(new ThemeInfo(currentMode, currentAccent));
    }
}

